//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  var strDate = $c.date.getServerDateTime($p, "yyyyMM");
  ed_wrkStDt.setValue(strDate);
  ed_wrkEndDt.setValue(strDate);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
  var validateChk = await $c.gus.cfValidate($p, [tb_wrk], null, true);
  if (!validateChk) return;
  if (ed_wrkEndDt.getValue() < ed_wrkStDt.getValue()) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오. 
    ed_wrkStDt.focus();
    return;
  }

  //ds_fix_work_re.UseChangeInfo = false; // 조회조건

  dma_fix_work_re.set("termFrom", ed_wrkStDt.getValue());
  dma_fix_work_re.set("termTo", ed_wrkEndDt.getValue());
  dma_fix_work_re.set("fixWrkPlCd", lc_wrkPlCd.getValue());
  dma_fix_work_re.set("eqCd", ed_eqCd.getValue());
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
    ds_crossTab.removeAll(); //초기화
    var rowCnt = ds_fix_work_list.getRowCount();

    //컬럼 차령 이후 모든 컬럼 hide => 컬럼초기화상태
    for (var i = 1; i < 192; i++) {
      gr_work_pl.setColumnVisible(`oprtHhCnt${i}`, false);
      gr_work_pl.setHeaderValue(`column${8 + i}`, "");
    }
    if (rowCnt == 0) {
      $c.win.alert($p, "조회된 데이터가 없습니다.");
      totalRows.setValue(0);
      return;
    }

    //crossTab 생성.
    var orignJson = ds_fix_work_list.getAllJSON();
    var allJson = [];
    var crossRJson = {};
    var coldata = [];
    orignJson.forEach(function (rowJson, index, orignArr) {
      //컬럼생성
      if (!coldata.includes(rowJson.ym)) {
        coldata.push(rowJson.ym);
      }
      if (coldata.length > 192) return; //동적으로 늘어나는 컬럼수가 192 이상이면 컬럼수 더 늘려서 구현하거나 피봇컴포넌트로 개발필요.(but, 컬럼 총 200개 이상시, 엑셀다운로드 안됨.)

      var rowKey = rowJson.eqKndCd + "_" + rowJson.branNm;
      if (!crossRJson[rowKey]) {
        crossRJson[rowKey] = rowJson;
      }
      let dateIdx = coldata.indexOf(rowJson.ym);
      if (dateIdx > -1) {
        crossRJson[rowKey]["oprtHhCnt" + dateIdx] = rowJson.oprtHhCnt;
      }
    });
    for (let key in crossRJson) {
      allJson.push(crossRJson[key]);
    }
    ds_crossTab.setJSON(allJson);
    var options = {};
    options.sortIndex = "branNm eqKndCd";
    options.sortOrder = "0 0";
    ds_crossTab.multisort(options);

    //컬럼갯수 만큼 show, 헤더 값 셋팅
    for (var i = 0; i < coldata.length; i++) {
      gr_work_pl.setHeaderValue(`column${i + 9}`, coldata[i], true);
      gr_work_pl.setColumnVisible(`oprtHhCnt${i}`, true);
    }

    //총갯수 표시
    totalRows.setValue(ds_crossTab.getRowCount());
  }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  var pWhere = "";
  switch (disGubun) {
    case 1:
      // 장비 팝업			
      await udc_eqCd.cfCommonPopUp(function (rtnList) {
        $c.gus.cfSetReturnValue($p, rtnList, ed_eqCd, ed_vehclNo);
      }, ed_eqCd.getValue().trim() // 화면에서의 Code Element의	Value
      , ed_vehclNo.getValue() // 화면에서의 Name Element의	Value
      , pClose // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
      , null // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
      , null // Title순서	
      , null // 보여주는 각 컬럼들의 폭	
      , null // 컬럼중에서 숨기는	컬럼 지정	
      , pWhere // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
      , "1000" // POP-UP뛰을때 원도우의	사용자 정의	폭
      , null // POP-UP뛰을때 우도우의	사용자 정의	높이	
      , null // 윈도우 위치 Y좌표	
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부	("F")
      , pAllSearch // 전체검색허용여부	("F")
      , "장비,장비코드,차량번호" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
      );
      break;
  }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!(await $c.gus.cfCanOpenPopup($p, inObj, pairObj))) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if ($c.gus.cfIsNull($p, isCode) || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
  } else {
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};

